  1→/**
  2→ * Observer Agent Acceptance Test Kit
  3→ *
  4→ * Extends the orchestrator-test-kit with observer-specific helpers.
  5→ * All helpers use business language -- no technical jargon in function names.
  6→ *
  7→ * Driving ports:
  8→ *   POST /api/observe/:table/:id        (SurrealQL EVENT target)
  9→ *   POST /api/observe/scan/:workspaceId  (periodic graph scan)
 10→ */
 11→import { RecordId, type Surreal } from "surrealdb";
 12→
 13→// Re-export everything from orchestrator-test-kit
 14→export {
 15→  setupOrchestratorSuite,
 16→  createTestUser,
 17→  createTestWorkspace,
 18→  createReadyTask,
 19→  createTestProject,
 20→  getTestUserBearerToken,
 21→  fetchJson,
 22→  fetchRaw,
 23→  type OrchestratorTestRuntime,
 24→  type TestUser,
 25→  type TestUserWithToken,
 26→  type TestWorkspace,
 27→  type TestTask,
 28→  type TestProject,
 29→} from "../coding-agent-orchestrator/orchestrator-test-kit";
 30→
 31→import {
 32→  fetchJson,
 33→  fetchRaw,
 34→  type TestUser,
 35→} from "../coding-agent-orchestrator/orchestrator-test-kit";
 36→
 37→// ---------------------------------------------------------------------------
 38→// Observer-Specific Types
 39→// ---------------------------------------------------------------------------
 40→
 41→export type ObservationSeverity = "info" | "warning" | "conflict";
 42→
 43→export type ObservationStatus = "open" | "acknowledged" | "resolved";
 44→
 45→export type ObservationType =
 46→  | "contradiction"
 47→  | "duplication"
 48→  | "missing"
 49→  | "deprecated"
 50→  | "pattern"
 51→  | "anomaly"
 52→  | "validation"
 53→  | "error";
 54→
 55→export type ObservationRecord = {
 56→  id: RecordId<"observation">;
 57→  text: string;
 58→  severity: ObservationSeverity;
 59→  status: ObservationStatus;
 60→  observation_type?: ObservationType;
 61→  source_agent: string;
 62→  verified?: boolean;
 63→  source?: string;
 64→  data?: Record<string, unknown>;
 65→  workspace: RecordId<"workspace">;
 66→  created_at: string;
 67→  updated_at?: string;
 68→};
 69→
 70→export type ObserverVerdict = "match" | "mismatch" | "inconclusive";
 71→
 72→export type CreateTaskWithCommitOptions = {
 73→  title: string;
 74→  description?: string;
 75→  status?: string;
 76→  sha?: string;
 77→  repository?: string;
 78→  prUrl?: string;
 79→};
 80→
 81→export type CreateGitCommitOptions = {
 82→  message?: string;
 83→  repository?: string;
 84→  authorName?: string;
 85→  url?: string;
 86→};
 87→
 88→export type CreateCompletedIntentOptions = {
 89→  goal: string;
 90→  reasoning: string;
 91→  actionSpec: { provider: string; action: string; params?: Record<string, unknown> };
 92→  status?: "completed" | "failed";
 93→};
 94→
 95→export type MockGitHubResponse = {
 96→  path: string;
 97→  status: number;
 98→  body: unknown;
 99→};
100→
101→// ---------------------------------------------------------------------------
102→// Suite Setup
103→// ---------------------------------------------------------------------------
104→
105→export { setupAcceptanceSuite } from "../acceptance-test-kit";
106→
107→import { setupAcceptanceSuite } from "../acceptance-test-kit";
108→
109→/**
110→ * Sets up an observer acceptance test suite with an isolated server + DB.
111→ */
112→export function setupObserverSuite(
113→  suiteName: string,
114→): () => import("../acceptance-test-kit").AcceptanceTestRuntime {
115→  return setupAcceptanceSuite(suiteName);
116→}
117→
118→// ---------------------------------------------------------------------------
119→// Domain Helpers -- Business Language Layer
120→// ---------------------------------------------------------------------------
121→
122→/**
123→ * Wires all 5 SurrealQL EVENTs for the observer agent.
124→ * Events POST to the test server's observe endpoint.
125→ *
126→ * Must be called in beforeAll after the test server has booted.
127→ */
128→export async function wireObserverEvents(
129→  surreal: Surreal,
130→  port: number,
131→): Promise<void> {
132→  const candidateHosts = process.env.OBSERVER_CALLBACK_HOST?.trim()
133→    ? [process.env.OBSERVER_CALLBACK_HOST.trim()]
134→    : ["127.0.0.1", "host.docker.internal"];
135→
136→  let baseUrl: string | undefined;
137→  let lastError = "";
138→
139→  for (const host of candidateHosts) {
140→    const candidateBaseUrl = `http://${host}:${port}`;
141→    try {
142→      await surreal.query(`RETURN http::head($url);`, {
143→        url: `${candidateBaseUrl}/healthz`,
144→      });
145→      baseUrl = candidateBaseUrl;
146→      break;
147→    } catch (error) {
148→      lastError = error instanceof Error ? error.message : String(error);
149→    }
150→  }
151→
152→  if (!baseUrl) {
153→    throw new Error(
154→      `Unable to reach acceptance server from SurrealDB for observer callback. ` +
155→      `Tried hosts: ${candidateHosts.join(", ")} on port ${port}. ` +
156→      `Last error: ${lastError}`,
157→    );
158→  }
159→
160→  // EVENT 1: task_completed — fires when task status transitions to completed/done
161→  await surreal.query(`
162→    DEFINE EVENT OVERWRITE task_completed ON task
163→      ASYNC
164→      RETRY 3
165→      WHEN $event = "UPDATE"
166→        AND ($before.status != "completed" AND $before.status != "done")
167→        AND ($after.status = "completed" OR $after.status = "done")
168→      THEN {
169→        http::post("${baseUrl}/api/observe/task/" + <string> meta::id($after.id), $after)
170→      };
171→  `);
172→
173→  // EVENT 2: intent_completed — fires when intent status transitions to completed/failed
174→  await surreal.query(`
175→    DEFINE EVENT OVERWRITE intent_completed ON intent
176→      ASYNC
177→      RETRY 3
178→      WHEN $event = "UPDATE"
179→        AND ($before.status != "completed" AND $before.status != "failed")
180→        AND ($after.status = "completed" OR $after.status = "failed")
181→      THEN {
182→        http::post("${baseUrl}/api/observe/intent/" + <string> meta::id($after.id), $after)
183→      };
184→  `);
185→
186→  // EVENT 3: commit_created — fires when a new git_commit record is created
187→  await surreal.query(`
188→    DEFINE EVENT OVERWRITE commit_created ON git_commit
189→      ASYNC
190→      RETRY 3
191→      WHEN $event = "CREATE"
192→      THEN {
193→        http::post("${baseUrl}/api/observe/git_commit/" + <string> meta::id($after.id), $after)
194→      };
195→  `);
196→
197→  // EVENT 4: decision_confirmed — fires when decision status changes to confirmed/superseded
198→  await surreal.query(`
199→    DEFINE EVENT OVERWRITE decision_confirmed ON decision
200→      ASYNC
201→      RETRY 3
202→      WHEN $event = "UPDATE"
203→        AND $before.status != $after.status
204→        AND ($after.status = "confirmed" OR $after.status = "superseded")
205→      THEN {
206→        http::post("${baseUrl}/api/observe/decision/" + <string> meta::id($after.id), $after)
207→      };
208→  `);
209→
210→  // EVENT 5: observation_peer_review — fires when non-observer observation is created
211→  await surreal.query(`
212→    DEFINE EVENT OVERWRITE observation_peer_review ON observation
213→      ASYNC
214→      RETRY 3
215→      WHEN $event = "CREATE" AND $after.source_agent != "observer_agent"
216→      THEN {
217→        http::post("${baseUrl}/api/observe/observation/" + <string> meta::id($after.id), $after)
218→      };
219→  `);
220→}
221→
222→/**
223→ * Creates a task linked to a source commit in the graph.
224→ * Used as a Given-step precondition for task verification scenarios.
225→ */
226→export async function createTaskWithCommit(
227→  surreal: Surreal,
228→  workspaceId: string,
229→  opts: CreateTaskWithCommitOptions,
230→): Promise<{ taskId: string; commitId: string; sha: string }> {
231→  const taskId = `task-${crypto.randomUUID()}`;
232→  const commitId = `commit-${crypto.randomUUID()}`;
233→  const sha = opts.sha ?? `abc${crypto.randomUUID().replace(/-/g, "").slice(0, 37)}`;
234→  const taskRecord = new RecordId("task", taskId);
235→  const commitRecord = new RecordId("git_commit", commitId);
236→  const workspaceRecord = new RecordId("workspace", workspaceId);
237→
238→  // Create the git_commit record (but NOT via CREATE if we want to avoid triggering commit_created EVENT)
239→  // Use a direct insert approach to seed without firing events
240→  await surreal.query(
241→    `CREATE $commit CONTENT $content;`,
242→    {
243→      commit: commitRecord,
244→      content: {
245→        sha,
246→        repository: opts.repository ?? "org/repo",
247→        message: `feat: ${opts.title}`,
248→        author_name: "test-agent",
249→        workspace: workspaceRecord,
250→        created_at: new Date(),
251→      },
252→    },
253→  );
254→
255→  // Create the task linked to the commit
256→  await surreal.query(
257→    `CREATE $task CONTENT $content;`,
258→    {
259→      task: taskRecord,
260→      content: {
261→        title: opts.title,
262→        description: opts.description ?? "Test task for observer verification",
263→        status: opts.status ?? "in_progress",
264→        source_commit: commitRecord,
265→        workspace: workspaceRecord,
266→        created_at: new Date(),
267→        updated_at: new Date(),
268→      },
269→    },
270→  );
271→
272→  return { taskId, commitId, sha };
273→}
274→
275→/**
276→ * Creates a git_commit record in the graph.
277→ * Note: if commit_created EVENT is wired, this WILL trigger the observer.
278→ */
279→export async function createGitCommit(
280→  surreal: Surreal,
281→  workspaceId: string,
282→  sha: string,
283→  opts?: CreateGitCommitOptions,
284→): Promise<{ commitId: string }> {
285→  const commitId = `commit-${crypto.randomUUID()}`;
286→  const commitRecord = new RecordId("git_commit", commitId);
287→  const workspaceRecord = new RecordId("workspace", workspaceId);
288→
289→  await surreal.query(
290→    `CREATE $commit CONTENT $content;`,
291→    {
292→      commit: commitRecord,
293→      content: {
294→        sha,
295→        repository: opts?.repository ?? "org/repo",
296→        message: opts?.message ?? "chore: test commit",
297→        author_name: opts?.authorName ?? "test-agent",
298→        url: opts?.url,
299→        workspace: workspaceRecord,
300→        created_at: new Date(),
301→      },
302→    },
303→  );
304→
305→  return { commitId };
306→}
307→
308→/**
309→ * Creates an intent that has reached completed or failed status.
310→ * Used as a Given-step precondition for intent verification scenarios.
311→ */
312→export async function createCompletedIntent(
313→  surreal: Surreal,
314→  workspaceId: string,
315→  requesterId: string,
316→  opts: CreateCompletedIntentOptions,
317→): Promise<{ intentId: string }> {
318→  const intentId = `intent-${crypto.randomUUID()}`;
319→  const intentRecord = new RecordId("intent", intentId);
320→  const workspaceRecord = new RecordId("workspace", workspaceId);
321→  const requesterRecord = new RecordId("identity", requesterId);
322→  const traceId = `trace-${intentId}`;
323→  const traceRecord = new RecordId("trace", traceId);
324→
325→  await surreal.query(`CREATE $trace CONTENT $content;`, {
326→    trace: traceRecord,
327→    content: {
328→      type: "intent_submission",
329→      actor: requesterRecord,
330→      workspace: workspaceRecord,
331→      created_at: new Date(),
332→    },
333→  });
334→
335→  await surreal.query(`CREATE $intent CONTENT $content;`, {
336→    intent: intentRecord,
337→    content: {
338→      goal: opts.goal,
339→      reasoning: opts.reasoning,
340→      status: opts.status ?? "completed",
341→      priority: 50,
342→      action_spec: opts.actionSpec,
343→      trace_id: traceRecord,
344→      requester: requesterRecord,
345→      workspace: workspaceRecord,
346→      evaluation: {
347→        decision: "APPROVE",
348→        risk_score: 10,
349→        reason: "Pre-approved for testing",
350→        evaluated_at: new Date(),
351→        policy_only: false,
352→      },
353→      created_at: new Date(),
354→    },
355→  });
356→
357→  return { intentId };
358→}
359→
360→/**
361→ * Creates an observation record directly in the database.
362→ * Used as a Given-step to seed observations from other agents for peer review testing.
363→ */
364→export async function createObservationByAgent(
365→  surreal: Surreal,
366→  workspaceId: string,
367→  sourceAgent: string,
368→  opts: {
369→    text: string;
370→    severity: ObservationSeverity;
371→    observationType?: ObservationType;
372→    targetTable?: string;
373→    targetId?: string;
374→  },
375→): Promise<{ observationId: string }> {
376→  const observationId = `obs-${crypto.randomUUID()}`;
377→  const observationRecord = new RecordId("observation", observationId);
378→  const workspaceRecord = new RecordId("workspace", workspaceId);
379→
380→  await surreal.query(`CREATE $obs CONTENT $content;`, {
381→    obs: observationRecord,
382→    content: {
383→      text: opts.text,
384→      severity: opts.severity,
385→      status: "open",
386→      observation_type: opts.observationType,
387→      source_agent: sourceAgent,
388→      workspace: workspaceRecord,
389→      created_at: new Date(),
390→    },
391→  });
392→
393→  // Link observation to target entity if provided
394→  if (opts.targetTable && opts.targetId) {
395→    const targetRecord = new RecordId(opts.targetTable, opts.targetId);
396→    await surreal.query(
397→      `RELATE $obs->observes->$target SET added_at = time::now();`,
398→      { obs: observationRecord, target: targetRecord },
399→    );
400→  }
401→
402→  return { observationId };
403→}
404→
405→/**
406→ * Creates a confirmed decision directly in the database.
407→ */
408→export async function createConfirmedDecision(
409→  surreal: Surreal,
410→  workspaceId: string,
411→  opts: {
412→    summary: string;
413→    rationale?: string;
414→    status?: string;
415→  },
416→): Promise<{ decisionId: string }> {
417→  const decisionId = `decision-${crypto.randomUUID()}`;
418→  const decisionRecord = new RecordId("decision", decisionId);
419→  const workspaceRecord = new RecordId("workspace", workspaceId);
420→
421→  await surreal.query(`CREATE $dec CONTENT $content;`, {
422→    dec: decisionRecord,
423→    content: {
424→      summary: opts.summary,
425→      rationale: opts.rationale ?? "Confirmed for testing",
426→      status: opts.status ?? "confirmed",
427→      workspace: workspaceRecord,
428→      created_at: new Date(),
429→      updated_at: new Date(),
430→    },
431→  });
432→
433→  return { decisionId };
434→}
435→
436→/**
